const p = msg.payload;
if (!p || typeof p !== "object") {
    return null;
}

const sensor = String(p.sensor || p.cihaz_id || p.device_id || "unknown").toLowerCase();

let sicaklik = p.sicaklik;
let nem = p.nem;

if (p.values && typeof p.values === "object") {
    if (sicaklik === undefined) sicaklik = p.values.sicaklik;
    if (nem === undefined) nem = p.values.nem;
}

const out = [];

if (sicaklik !== undefined && sicaklik !== null && !Number.isNaN(Number(sicaklik))) {
    out.push({ payload: Number(sicaklik), topic: "sicaklik_gauge" });
}

if (nem !== undefined && nem !== null && !Number.isNaN(Number(nem))) {
    out.push({ payload: Number(nem), topic: "nem_gauge" });
}

if (sensor.includes("ds18") || sensor === "ds18b20") {
    if (sicaklik !== undefined) {
        out.push({ payload: Number(sicaklik), topic: "ds18b20" });
    }
} else if (sensor.includes("dht") || sensor === "dht11") {
    if (sicaklik !== undefined) {
        out.push({ payload: Number(sicaklik), topic: "dht11" });
    }
    if (nem !== undefined) {
        out.push({ payload: Number(nem), topic: "dht11" });
    }
} else {
    if (nem !== undefined) {
        if (sicaklik !== undefined) {
            out.push({ payload: Number(sicaklik), topic: "dht11" });
        }
        out.push({ payload: Number(nem), topic: "dht11" });
    } else if (sicaklik !== undefined) {
        out.push({ payload: Number(sicaklik), topic: "ds18b20" });
    }
}

if (out.length === 0) {
    return null;
}

node.send(out);
return null;
